// src/pages/admin/AdminDashboard.js
import React, { useEffect, useState } from "react";
import {
  getOverview,
  getUsers,
  getRiders,
  getApprovedCaptains,
  getPendingCaptains,
  approveCaptain,
  rejectCaptain,
  getRides,
} from "../../services/adminApi";
import {
  Box,
  Paper,
  Typography,
  Grid,
  Button,
  Table,
  TableHead,
  TableBody,
  TableRow,
  TableCell,
  IconButton,
} from "@mui/material";
import PeopleIcon from "@mui/icons-material/People";
import EmojiPeopleIcon from "@mui/icons-material/EmojiPeople";
import PendingActionsIcon from "@mui/icons-material/PendingActions";
import VerifiedUserIcon from "@mui/icons-material/VerifiedUser";
import LocalTaxiIcon from "@mui/icons-material/LocalTaxi";
import LogoutIcon from "@mui/icons-material/Logout";

import { useAuth } from "../../contexts/AuthContext";
import { useNavigate } from "react-router-dom";

export default function AdminDashboard() {
  const [overview, setOverview] = useState({});
  const [users, setUsers] = useState([]);
  const [riders, setRiders] = useState([]);
  const [approvedCaptains, setApprovedCaptains] = useState([]);
  const [pendingCaptains, setPendingCaptains] = useState([]);
  const [rides, setRides] = useState([]);
  const [loading, setLoading] = useState(true);

  const { logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate("/admin");
  };

  const fetchData = async () => {
    try {
      setLoading(true);
      const [overviewRes, usersRes, ridersRes, approvedRes, pendingRes, ridesRes] =
        await Promise.all([
          getOverview(),
          getUsers(),
          getRiders(),
          getApprovedCaptains(),
          getPendingCaptains(),
          getRides(),
        ]);

      setOverview(overviewRes.data);
      setUsers(usersRes.data.users);
      setRiders(ridersRes.data.riders);
      setApprovedCaptains(approvedRes.data.captains);
      setPendingCaptains(pendingRes.data.pendingCaptains);
      setRides(ridesRes.data.rides);
    } catch (err) {
      console.error("Admin Dashboard API error:", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleApprove = async (id) => {
    await approveCaptain(id);
    fetchData();
  };

  const handleReject = async (id) => {
    await rejectCaptain(id);
    fetchData();
  };

  if (loading) return <Typography>Loading...</Typography>;

  const cardData = [
    { label: "Users", value: overview.users, icon: <PeopleIcon fontSize="large" color="primary" /> },
    { label: "Riders", value: overview.riders, icon: <EmojiPeopleIcon fontSize="large" color="success" /> },
    { label: "Approved Captains", value: overview.captains, icon: <VerifiedUserIcon fontSize="large" color="secondary" /> },
    { label: "Pending Captains", value: overview.pendingCaptains, icon: <PendingActionsIcon fontSize="large" color="warning" /> },
    { label: "Total Rides", value: overview.rides, icon: <LocalTaxiIcon fontSize="large" color="error" /> },
  ];

  const renderTable = (data, title, isPending = false) => (
    <Paper sx={{ p: 2, mt: 3 }}>
      <Typography variant="h6" gutterBottom>{title}</Typography>
      <Table>
        <TableHead>
          <TableRow>
            <TableCell>Name</TableCell>
            <TableCell>Email</TableCell>
            <TableCell>Mobile</TableCell>
            <TableCell>Role</TableCell>
            <TableCell>Login Count</TableCell>
            <TableCell>Approval Status</TableCell>
            {isPending && <TableCell>Actions</TableCell>}
          </TableRow>
        </TableHead>
        <TableBody>
          {data.length === 0 ? (
            <TableRow>
              <TableCell colSpan={isPending ? 7 : 6} align="center">No data found</TableCell>
            </TableRow>
          ) : (
            data.map((item) => (
              <TableRow key={item._id}>
                <TableCell>{item.fullName}</TableCell>
                <TableCell>{item.email}</TableCell>
                <TableCell>{item.mobile}</TableCell>
                <TableCell>{item.role}</TableCell>
                <TableCell>{item.loginCount || 0}</TableCell>
                <TableCell>{item.approvalStatus}</TableCell>
                {isPending && (
                  <TableCell>
                    <Button variant="contained" color="success" size="small" onClick={() => handleApprove(item._id)} sx={{ mr: 1 }}>
                      Approve
                    </Button>
                    <Button variant="contained" color="error" size="small" onClick={() => handleReject(item._id)}>
                      Reject
                    </Button>
                  </TableCell>
                )}
              </TableRow>
            ))
          )}
        </TableBody>
      </Table>
    </Paper>
  );

  return (
    <Box>
      <Box display="flex" justifyContent="space-between" alignItems="center" mb={2}>
        <Typography variant="h4">Admin Dashboard</Typography>
        <Button variant="outlined" color="secondary" startIcon={<LogoutIcon />} onClick={handleLogout}>
          Logout
        </Button>
      </Box>

      <Grid container spacing={2}>
        {cardData.map((card) => (
          <Grid item xs={12} sm={6} md={2.4} key={card.label}>
            <Paper sx={{ p: 2, display: "flex", alignItems: "center", gap: 1 }}>
              {card.icon}
              <Box>
                <Typography variant="h6">{card.value}</Typography>
                <Typography variant="body2">{card.label}</Typography>
              </Box>
            </Paper>
          </Grid>
        ))}
      </Grid>

      {renderTable(users, "Users")}
      {renderTable(riders, "Riders")}
      {renderTable(approvedCaptains, "Approved Captains")}
      {renderTable(pendingCaptains, "Pending Captains", true)}
    </Box>
  );
}
